import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

import java.net.InetAddress;
import java.util.Arrays;
import java.util.List;

@RestController
@RequestMapping("/webhook")
public class WebhookController {

    @Autowired
    private RestTemplate restTemplate;

    private static final List<String> ALLOWLIST = Arrays.asList(
        "http://example.com",
        "https://api.example.com"
    );

    @PostMapping("/fetch")
    public ResponseEntity<String> fetchContent(@RequestBody String url) {
        if (!isValidUrl(url)) {
            return ResponseEntity.badRequest().body("URL is not allowed");
        }

        HttpHeaders headers = new HttpHeaders();
        HttpEntity<String> entity = new HttpEntity<>(headers);

        try {
            ResponseEntity<String> response = restTemplate.exchange(url, HttpMethod.GET, entity, String.class);
            return ResponseEntity.ok(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Failed to fetch content");
        }
    }

    private boolean isValidUrl(String url) {
        try {
            InetAddress address = InetAddress.getByName(new java.net.URL(url).getHost());
            String hostAddress = address.getHostAddress();
            if (hostAddress.equals("127.0.0.1") ||
                hostAddress.startsWith("192.168.") ||
                hostAddress.startsWith("10.")) {
                return false;
            }
        } catch (Exception e) {
            return false;
        }

        return ALLOWLIST.contains(url);
    }
}